const input = $('When Executed by Another Workflow').first().json || {};

const config = {
  boardId: 1041,
  jiraBaseUrl: 'https://atlassiansuite.mservice.com.vn:8443',
  timeZone: 'Asia/Ho_Chi_Minh',
  storyPointFieldKey: 'customfield_10107',
  qcsFieldKey: 'customfield_10201',
  spreadsheetId: '1uLVZ2b6Ra-r2KCbLHcOL68V6smtxymfTCNNQnWPG8mI',
  spreadsheetSheetName: 'MoMoer',
  boardOwnerEmails: [],
  passedStatusesForReleaseGate: ['Ready For Release', 'Close', 'Closed'],
  pendingActionTtlHours: 24,
  nowIso: $now.setZone('Asia/Ho_Chi_Minh').toISO(),
  todayDate: $now.setZone('Asia/Ho_Chi_Minh').toFormat('yyyy-MM-dd'),
};

function toText(value) {
  if (typeof value === 'string') return value.trim();
  if (value == null) return '';
  return String(value).trim();
}

function parseArgs(value) {
  return value && typeof value === 'object' && !Array.isArray(value) ? value : {};
}

function detectCommandType(commandText, rawType) {
  const fromArgs = toText(rawType).toLowerCase();
  if (fromArgs) return fromArgs;

  const normalized = toText(commandText).toLowerCase();
  if (/release\s+sprint|close\s+sprint|release\s+status/i.test(normalized)) return 'release_sprint';
  if (/(^|\b)(approve|ok|dong y|đồng ý|xac nhan|xác nhận)(\b|$)/i.test(normalized)) return 'approve';
  if (/(^|\b)(reject|tu choi|từ chối)(\b|$)/i.test(normalized)) return 'reject';
  if (/(^|\b)(cancel|huy|hủy)(\b|$)/i.test(normalized)) return 'cancel';
  return 'help';
}

const args = parseArgs(input.args);

return {
  ...input,
  args,
  config,
  commandType: detectCommandType(input.commandText, args.commandType),
};

const input = $('Get Active Sprint').first().json || {};
const root = $('Config Main').first().json || {};

function toText(value) {
  if (typeof value === 'string') return value.trim();
  if (value == null) return '';
  return String(value).trim();
}

const statusCode = Number(input.statusCode || 200);
const transportError = toText(input.error?.message || input.error?.description || input.message || '');

if (transportError && !input.body) {
  return {
    ...root,
    hasActiveSprint: false,
    sprint: null,
    failureReason: 'Không kết nối được Jira host: ' + transportError,
  };
}

if (statusCode >= 400) {
  return {
    ...root,
    hasActiveSprint: false,
    sprint: null,
    failureReason: 'Không lấy được active sprint từ Jira (HTTP ' + statusCode + ')',
  };
}

const body = input.body && typeof input.body === 'object' ? input.body : input;
const values = Array.isArray(body.values) ? body.values : [];
const active = values
  .filter((item) => String(item?.state || '').toLowerCase() === 'active')
  .sort((a, b) => new Date(b?.startDate || 0).getTime() - new Date(a?.startDate || 0).getTime())[0] || null;

if (!active) {
  return {
    ...root,
    hasActiveSprint: false,
    sprint: null,
    failureReason: 'Không tìm thấy active sprint cho board ' + String(root.config?.boardId || 1041),
  };
}

return {
  ...root,
  hasActiveSprint: true,
  sprint: {
    id: active.id,
    name: active.name || '',
    startDate: active.startDate || '',
    endDate: active.endDate || '',
  },
};

const ctx = $('Pick Active Sprint').first().json || {};
const sessionResult = $('Load Session').first().json || {};
const pendingResult = $('Get Pending Action').first().json || {};
const issueResponse = $('Get Sprint Issues').first().json || {};
const users = $input.all().map((item) => (item?.json && typeof item.json === 'object' ? item.json : {}));

function toText(value) {
  if (typeof value === 'string') return value.trim();
  if (value == null) return '';
  return String(value).trim();
}

function asObject(value) {
  return value && typeof value === 'object' && !Array.isArray(value) ? value : {};
}

function normalizeEmail(value) {
  const email = toText(value).toLowerCase();
  return email.includes('@') ? email : '';
}

function normalizeStatus(raw) {
  const status = toText(raw).toLowerCase();
  const map = {
    open: 'Open',
    'in progress': 'In Progress',
    'ready for test': 'Ready For Test',
    'in test': 'In Test',
    'ready for review': 'Ready For Review',
    'in review': 'In Review',
    'ready for release': 'Ready For Release',
    close: 'Close',
    closed: 'Close',
    done: 'Close',
  };
  return map[status] || toText(raw);
}

function mentionFromDirectory(name, email, mentionMap) {
  const normalizedEmail = normalizeEmail(email);
  if (normalizedEmail && mentionMap[normalizedEmail]) return '<users/' + mentionMap[normalizedEmail] + '>';
  if (name) return '@' + name;
  if (normalizedEmail) return '@' + normalizedEmail;
  return '@Unknown';
}

const mentionMap = {};
for (const row of users) {
  const normalized = {};
  for (const [key, value] of Object.entries(row || {})) {
    normalized[toText(key).toLowerCase()] = value;
  }
  const email = normalizeEmail(normalized.email);
  const id = toText(normalized.id);
  if (!email || !id || mentionMap[email]) continue;
  mentionMap[email] = id;
}

const session = sessionResult?.found ? sessionResult.row : null;
const pendingAction = pendingResult?.found ? pendingResult.row : null;
const activePendingActionId = toText(session?.activePendingActionId || '');
const commandType = toText(ctx.commandType || '').toLowerCase();

const issueBody = issueResponse.body && typeof issueResponse.body === 'object' ? issueResponse.body : issueResponse;
const rawIssues = Array.isArray(issueBody.issues) ? issueBody.issues : [];

const passedStatuses = new Set((Array.isArray(ctx.config?.passedStatusesForReleaseGate) ? ctx.config.passedStatusesForReleaseGate : ['Ready For Release', 'Close', 'Closed']).map((status) => normalizeStatus(status)));
const finalStatuses = new Set(['Close']);
const blockers = [];
const missingFixVersion = [];
const versionsById = new Map();
const transitionCandidates = [];

const jiraBaseUrl = toText(ctx.config?.jiraBaseUrl).replace(/\/+$/, '');
const qcsField = toText(ctx.config?.qcsFieldKey || 'customfield_10201');

for (const issue of rawIssues) {
  const fields = asObject(issue?.fields);
  const issueType = toText(fields.issuetype?.name);
  if (!['Task', 'Bug'].includes(issueType)) continue;

  const key = toText(issue.key);
  const summary = toText(fields.summary || key || 'No summary');
  const status = normalizeStatus(fields.status?.name || '');
  const issueUrl = key && jiraBaseUrl ? jiraBaseUrl + '/browse/' + key : toText(issue.self || '');

  const assigneeName = toText(fields.assignee?.displayName || fields.assignee?.name || '');
  const assigneeEmail = normalizeEmail(fields.assignee?.emailAddress || fields.assignee?.email || '');
  const reporterName = toText(fields.reporter?.displayName || fields.creator?.displayName || '');
  const reporterEmail = normalizeEmail(fields.reporter?.emailAddress || fields.creator?.emailAddress || '');

  const qcsRaw = fields[qcsField];
  const qcs = Array.isArray(qcsRaw) ? qcsRaw : qcsRaw ? [qcsRaw] : [];
  const qcName = toText(qcs[0]?.displayName || qcs[0]?.name || '');
  const qcEmail = normalizeEmail(qcs[0]?.emailAddress || qcs[0]?.email || '');

  if (!passedStatuses.has(status)) {
    let ownerRole = 'REPORTER';
    let ownerName = reporterName;
    let ownerEmail = reporterEmail;

    if (status === 'Open' || status === 'In Progress') {
      ownerRole = 'DEV';
      ownerName = assigneeName || reporterName;
      ownerEmail = assigneeEmail || reporterEmail;
    } else if (status === 'Ready For Test' || status === 'In Test') {
      ownerRole = 'QC';
      ownerName = qcName || reporterName;
      ownerEmail = qcEmail || reporterEmail;
    }

    blockers.push({
      key,
      summary,
      status,
      role: ownerRole,
      mention: mentionFromDirectory(ownerName, ownerEmail, mentionMap),
      issueUrl,
    });
  }

  const isFinal = finalStatuses.has(status);
  if (!isFinal) {
    transitionCandidates.push({ key, summary, status, issueUrl });
  }

  const isAppIssue = /\[(APP|FE)\]/i.test(summary) || /app/i.test(assigneeName);
  const fixVersions = Array.isArray(fields.fixVersions) ? fields.fixVersions : [];
  if (isAppIssue && fixVersions.length === 0) {
    missingFixVersion.push({ key, summary, issueUrl });
  }

  for (const fixVersion of fixVersions) {
    const versionId = toText(fixVersion.id);
    if (!versionId || Boolean(fixVersion.released)) continue;

    if (!versionsById.has(versionId)) {
      versionsById.set(versionId, {
        id: versionId,
        name: toText(fixVersion.name || versionId),
        description: toText(fixVersion.description || ''),
        issueNotes: [],
      });
    }
    versionsById.get(versionId).issueNotes.push(key + ': ' + summary);
  }
}

const blockerJql = 'sprint = ' + String(ctx.sprint?.id || '') + ' AND issuetype in (Task,Bug) AND status NOT IN ("Ready For Release","Close","Closed")';
const blockerFilterUrl = jiraBaseUrl ? jiraBaseUrl + '/issues/?jql=' + encodeURIComponent(blockerJql) : '';

const missingFixKeys = missingFixVersion.map((item) => item.key).filter(Boolean);
const missingFixJql = missingFixKeys.length > 0
  ? 'key in (' + missingFixKeys.join(',') + ')'
  : 'sprint = ' + String(ctx.sprint?.id || '') + ' AND issuetype in (Task,Bug) AND fixVersion is EMPTY';
const missingFixFilterUrl = jiraBaseUrl ? jiraBaseUrl + '/issues/?jql=' + encodeURIComponent(missingFixJql) : '';

const boardOwners = (Array.isArray(ctx.config?.boardOwnerEmails) ? ctx.config.boardOwnerEmails : [])
  .map((email) => {
    const normalizedEmail = normalizeEmail(email);
    if (!normalizedEmail) return '';
    if (mentionMap[normalizedEmail]) return '<users/' + mentionMap[normalizedEmail] + '>';
    return '@' + normalizedEmail;
  })
  .filter(Boolean);

const now = new Date(toText(ctx.config?.nowIso) || new Date().toISOString());
const pendingExpiryHours = Math.max(1, Number(ctx.config?.pendingActionTtlHours || 24));
const expiresAt = new Date(now.getTime() + pendingExpiryHours * 3600 * 1000).toISOString();

const hasPending = Boolean(pendingAction && pendingAction.pendingActionId && String(pendingAction.approvalStatus || '').toLowerCase() === 'pending');
const pendingExpired = hasPending
  ? (pendingAction.expiresAt ? new Date(pendingAction.expiresAt).getTime() < now.getTime() : false)
  : false;

let action = 'noop';
let reason = '';
let bypassGate = false;

if (commandType === 'release_sprint') {
  action = blockers.length > 0 || missingFixVersion.length > 0 ? 'blocked' : 'execute';
} else if (commandType === 'approve') {
  if (hasPending && !pendingExpired) {
    action = 'execute';
    bypassGate = true;
  } else {
    action = 'noop';
    reason = 'Không có pending action hợp lệ để approve trong thread này.';
  }
} else if (commandType === 'reject' || commandType === 'cancel') {
  if (hasPending && !pendingExpired) {
    action = 'close_pending';
  } else {
    action = 'noop';
    reason = 'Không có pending action để reject/cancel trong thread này.';
  }
} else {
  action = 'help';
  reason = 'Lệnh chưa hỗ trợ. Dùng: release sprint | approve | reject | cancel';
}

const pendingActionId = hasPending && !pendingExpired
  ? toText(pendingAction.pendingActionId)
  : 'pending-release-' + Date.now().toString(36) + '-' + Math.random().toString(36).slice(2, 8);

const pendingActionPayload = action === 'blocked'
  ? {
      pendingActionId,
      sessionId: toText(ctx.sessionId || ''),
      toolName: 'sprintRelease',
      approvalStatus: 'pending',
      requestedBy: toText(ctx.actorId || ctx.actorDisplayName || ''),
      requestSummary: 'Release sprint ' + toText(ctx.sprint?.name || ctx.sprint?.id || ''),
      targetType: 'sprint',
      targetId: toText(ctx.sprint?.id || ''),
      executePayload: {
        triggerCommand: 'release_sprint',
        bypassGateOnApprove: true,
        sprintId: toText(ctx.sprint?.id || ''),
      },
      expiresAt,
      approvedBy: '',
      approvedAt: '',
      executedAt: '',
      executionStatus: '',
      idempotencyKey: 'release-' + toText(ctx.sessionId || '') + '-' + toText(ctx.sprint?.id || ''),
      approvalPrompt: 'Reply approve để tiếp tục release, reject/cancel để huỷ.',
    }
  : null;

const closePendingPayload = action === 'close_pending'
  ? {
      pendingActionId: toText(pendingAction?.pendingActionId || ''),
      sessionId: toText(pendingAction?.sessionId || ctx.sessionId || ''),
      toolName: toText(pendingAction?.toolName || 'sprintRelease'),
      approvalStatus: commandType === 'reject' ? 'rejected' : 'cancelled',
      requestedBy: toText(pendingAction?.requestedBy || ''),
      requestSummary: toText(pendingAction?.requestSummary || ''),
      targetType: toText(pendingAction?.targetType || 'sprint'),
      targetId: toText(pendingAction?.targetId || ''),
      executePayload: asObject(pendingAction?.executePayload || {}),
      expiresAt: toText(pendingAction?.expiresAt || ''),
      approvedBy: toText(ctx.actorId || ctx.actorDisplayName || ''),
      approvedAt: toText(ctx.config?.nowIso || ''),
      executedAt: '',
      executionStatus: commandType === 'reject' ? 'rejected' : 'cancelled',
      idempotencyKey: toText(pendingAction?.idempotencyKey || ''),
      approvalPrompt: toText(pendingAction?.approvalPrompt || ''),
    }
  : null;

const approvePendingPayload = action === 'execute' && bypassGate && hasPending
  ? {
      pendingActionId: toText(pendingAction.pendingActionId),
      sessionId: toText(pendingAction.sessionId || ctx.sessionId || ''),
      toolName: toText(pendingAction.toolName || 'sprintRelease'),
      approvalStatus: 'approved',
      requestedBy: toText(pendingAction.requestedBy || ''),
      requestSummary: toText(pendingAction.requestSummary || ''),
      targetType: toText(pendingAction.targetType || 'sprint'),
      targetId: toText(pendingAction.targetId || ''),
      executePayload: asObject(pendingAction.executePayload || {}),
      expiresAt: toText(pendingAction.expiresAt || ''),
      approvedBy: toText(ctx.actorId || ctx.actorDisplayName || ''),
      approvedAt: toText(ctx.config?.nowIso || ''),
      executedAt: '',
      executionStatus: 'approved',
      idempotencyKey: toText(pendingAction.idempotencyKey || ''),
      approvalPrompt: toText(pendingAction.approvalPrompt || ''),
    }
  : null;

return [{
  json: {
    ...ctx,
    session,
    pendingAction,
    activePendingActionId,
    mentionMap,
    blockers,
    blockerFilterUrl,
    missingFixVersion,
    missingFixFilterUrl,
    boardOwners,
    transitionCandidates,
    versionsToRelease: Array.from(versionsById.values()),
    action,
    reason,
    bypassGate,
    pendingActionPayload,
    closePendingPayload,
    approvePendingPayload,
  },
}];

const context = $('Build Release Context').first().json || {};

function normalizeDestinations(raw, triggerSource) {
  const defaults = triggerSource === 'schedule' ? [{ type: 'pushGoogleChat' }] : [{ type: 'reply' }];
  const source = [...defaults, ...(Array.isArray(raw) ? raw : [])];
  const seen = new Set();
  const normalized = [];
  for (const entry of source) {
    const type = typeof entry === 'string' ? entry.trim() : String(entry?.type || '').trim();
    if (!type || seen.has(type)) continue;
    seen.add(type);
    normalized.push({ type });
  }
  return normalized.length > 0 ? normalized : [{ type: 'reply' }];
}

const sprintLabel = String(context.sprint?.name || context.sprint?.id || 'Sprint chưa xác định');
const blockers = Array.isArray(context.blockers) ? context.blockers : [];
const missingFix = Array.isArray(context.missingFixVersion) ? context.missingFixVersion : [];
const boardOwners = Array.isArray(context.boardOwners) ? context.boardOwners : [];

const lines = [
  '⛔ Release sprint bị chặn: ' + sprintLabel,
  '',
  '- Blocker review: ' + blockers.length,
  ...(blockers.length > 0 ? blockers.map((item) => '- [' + item.role + '] ' + item.mention + ' <' + item.issueUrl + '|' + item.key + '> ' + item.summary + ' (' + item.status + ')') : ['- Không có blocker review']),
  '',
  '- App issue thiếu fixVersion: ' + missingFix.length,
  ...(missingFix.length > 0 ? missingFix.map((item) => '- <' + item.issueUrl + '|' + item.key + '> ' + item.summary) : ['- Không có issue app thiếu fixVersion']),
];

if (context.blockerFilterUrl) lines.push('', 'Link filter blocker: ' + context.blockerFilterUrl);
if (context.missingFixFilterUrl) lines.push('Link filter thiếu fixVersion: ' + context.missingFixFilterUrl);
if (boardOwners.length > 0) lines.push('', 'Board owners: ' + boardOwners.join(' '));
lines.push('', 'Reply approve để bypass gate và tiếp tục release, hoặc reject/cancel để huỷ.');

const text = lines.join('\n');
const destinations = normalizeDestinations(context.args?.additionalDestinations, context.triggerSource);
const destinationTypes = destinations.map((item) => item.type);

return [{
  json: {
    toolName: 'sprintRelease',
    resultText: text,
    activePendingActionId: String(context.pendingActionPayload?.pendingActionId || '').trim(),
    deliveryPlan: {
      thread: { threadKey: context.threadKey || 'sprint-release-' + Date.now().toString(36) },
      destinations,
      messages: [
        {
          messageKey: 'releaseBlocked',
          type: 'text',
          destinations: destinationTypes,
          payload: { text },
        },
      ],
    },
  },
}];

const context = $('Build Release Context').first().json || {};

function normalizeDestinations(raw, triggerSource) {
  const defaults = triggerSource === 'schedule' ? [{ type: 'pushGoogleChat' }] : [{ type: 'reply' }];
  const source = [...defaults, ...(Array.isArray(raw) ? raw : [])];
  const seen = new Set();
  const normalized = [];
  for (const entry of source) {
    const type = typeof entry === 'string' ? entry.trim() : String(entry?.type || '').trim();
    if (!type || seen.has(type)) continue;
    seen.add(type);
    normalized.push({ type });
  }
  return normalized.length > 0 ? normalized : [{ type: 'reply' }];
}

const text = context.commandType === 'reject'
  ? 'Đã reject pending action release sprint trong thread này.'
  : 'Đã cancel pending action release sprint trong thread này.';

const destinations = normalizeDestinations(context.args?.additionalDestinations, context.triggerSource);
const destinationTypes = destinations.map((item) => item.type);

return [{
  json: {
    toolName: 'sprintRelease',
    resultText: text,
    activePendingActionId: '',
    deliveryPlan: {
      thread: { threadKey: context.threadKey || 'sprint-release-' + Date.now().toString(36) },
      destinations,
      messages: [
        {
          messageKey: 'releasePendingClosed',
          type: 'text',
          destinations: destinationTypes,
          payload: { text },
        },
      ],
    },
  },
}];

const context = $('Build Release Context').first().json || {};

function normalizeDestinations(raw, triggerSource) {
  const defaults = triggerSource === 'schedule' ? [{ type: 'pushGoogleChat' }] : [{ type: 'reply' }];
  const source = [...defaults, ...(Array.isArray(raw) ? raw : [])];
  const seen = new Set();
  const normalized = [];
  for (const entry of source) {
    const type = typeof entry === 'string' ? entry.trim() : String(entry?.type || '').trim();
    if (!type || seen.has(type)) continue;
    seen.add(type);
    normalized.push({ type });
  }
  return normalized.length > 0 ? normalized : [{ type: 'reply' }];
}

const text = String(context.reason || 'Không có hành động cần xử lý.').trim();
const destinations = normalizeDestinations(context.args?.additionalDestinations, context.triggerSource);
const destinationTypes = destinations.map((item) => item.type);

return [{
  json: {
    toolName: 'sprintRelease',
    resultText: text,
    activePendingActionId: String(context.activePendingActionId || '').trim(),
    deliveryPlan: {
      thread: { threadKey: context.threadKey || 'sprint-release-' + Date.now().toString(36) },
      destinations,
      messages: [
        {
          messageKey: 'releaseNoop',
          type: 'text',
          destinations: destinationTypes,
          payload: { text },
        },
      ],
    },
  },
}];

const context = $('Pick Active Sprint').first().json || {};

function normalizeDestinations(raw, triggerSource) {
  const defaults = triggerSource === 'schedule' ? [{ type: 'pushGoogleChat' }] : [{ type: 'reply' }];
  const source = [...defaults, ...(Array.isArray(raw) ? raw : [])];
  const seen = new Set();
  const normalized = [];
  for (const entry of source) {
    const type = typeof entry === 'string' ? entry.trim() : String(entry?.type || '').trim();
    if (!type || seen.has(type)) continue;
    seen.add(type);
    normalized.push({ type });
  }
  return normalized.length > 0 ? normalized : [{ type: 'reply' }];
}

const text = String(context.failureReason || 'Không tìm thấy active sprint.').trim();
const destinations = normalizeDestinations(context.args?.additionalDestinations, context.triggerSource);
const destinationTypes = destinations.map((item) => item.type);

return [{
  json: {
    toolName: 'sprintRelease',
    resultText: text,
    activePendingActionId: String(context.activePendingActionId || '').trim(),
    deliveryPlan: {
      thread: { threadKey: context.threadKey || 'sprint-release-' + Date.now().toString(36) },
      destinations,
      messages: [
        {
          messageKey: 'releaseNoActiveSprint',
          type: 'text',
          destinations: destinationTypes,
          payload: { text },
        },
      ],
    },
  },
}];

const context = $('Build Release Context').first().json || {};

return [{
  json: {
    ...context,
    transitionSummary: null,
    versionSummary: null,
    completeSprintResult: null,
    nextSprintResult: null,
  },
}];

const payload = $('Build Execute Seed').first().json || {};
const candidates = Array.isArray(payload.transitionCandidates) ? payload.transitionCandidates : [];

return candidates.map((candidate, index) => ({
  json: {
    ...payload,
    transitionItem: {
      index,
      key: String(candidate.key || '').trim(),
      status: String(candidate.status || '').trim(),
      summary: String(candidate.summary || '').trim(),
      issueUrl: String(candidate.issueUrl || '').trim(),
    },
  },
}));

const response = $('Get Issue Transitions').first().json || {};
const item = $input.first().json || {};
const transitionItem = item.transitionItem || {};

function toText(value) {
  if (typeof value === 'string') return value.trim();
  if (value == null) return '';
  return String(value).trim();
}

function scoreTransition(name) {
  const normalized = toText(name).toLowerCase();
  if (normalized === 'close') return 100;
  if (normalized === 'closed') return 90;
  if (normalized === 'done') return 80;
  if (normalized === 'resolve issue') return 70;
  if (normalized.includes('close')) return 60;
  if (normalized.includes('done')) return 50;
  return 0;
}

const statusCode = Number(response.statusCode || 200);
const body = response.body && typeof response.body === 'object' ? response.body : response;
const transitions = Array.isArray(body.transitions) ? body.transitions : [];

if (statusCode >= 400) {
  return [{
    json: {
      ...item,
      transitionDecision: {
        canRun: false,
        issueKey: toText(transitionItem.key),
        issueUrl: toText(transitionItem.issueUrl),
        issueSummary: toText(transitionItem.summary),
        reason: 'Lỗi lấy transitions (HTTP ' + statusCode + ')',
      },
    },
  }];
}

const picked = transitions
  .map((transition) => ({ transition, score: scoreTransition(transition?.name) }))
  .sort((a, b) => b.score - a.score)[0];

if (!picked || picked.score <= 0 || !picked.transition?.id) {
  return [{
    json: {
      ...item,
      transitionDecision: {
        canRun: false,
        issueKey: toText(transitionItem.key),
        issueUrl: toText(transitionItem.issueUrl),
        issueSummary: toText(transitionItem.summary),
        reason: 'Không tìm thấy transition phù hợp (Close/Closed/Done)',
      },
    },
  }];
}

const transition = picked.transition;
const payload = {
  transition: {
    id: toText(transition.id),
  },
};

const resolutionField = transition.fields && transition.fields.resolution ? transition.fields.resolution : null;
if (resolutionField && resolutionField.required) {
  const allowedValues = Array.isArray(resolutionField.allowedValues) ? resolutionField.allowedValues : [];
  const first = allowedValues[0] || null;
  if (!first) {
    return [{
      json: {
        ...item,
        transitionDecision: {
          canRun: false,
          issueKey: toText(transitionItem.key),
          issueUrl: toText(transitionItem.issueUrl),
          issueSummary: toText(transitionItem.summary),
          reason: 'Transition yêu cầu resolution nhưng không có allowedValues',
        },
      },
    }];
